// 파이프라인 요청 파싱 (alert-channel-monitor에서 프로젝트 정보 전달받음)
const body = $input.item.json.body || $input.item.json;

// 프로젝트 정보 (projects.json에서 이미 조회됨)
const projectId = body.projectId;
const projectName = body.projectName;
const jiraProject = body.jiraProject || 'PROJ';  // projects.json의 jiraProject
const gitlabPath = body.gitlabPath;
const workingDirectory = body.workingDirectory;
const defaultBranch = body.defaultBranch || 'develop';

// 분석 결과
const summary = body.summary;
const description = body.description;
const severity = body.severity || 'HIGH';
const suggestedFix = body.suggestedFix;
const errorType = body.errorType;

// Slack 정보
const channel = body.channel;
const threadTs = body.threadTs;
const userId = body.userId;

// 워크스페이스 경로 (환경변수 폴백)
const workspacePath = process.env.WORKSPACE_PATH || '/workspace';
const projectPath = workingDirectory || `${workspacePath}/${projectId}`;

return {
  json: {
    projectId,
    projectName,
    projectPath,
    jiraProject,
    gitlabPath,
    baseBranch: defaultBranch,
    summary,
    description,
    severity,
    suggestedFix,
    errorType,
    channel,
    threadTs,
    userId
  }
};

const jiraResponse = $input.item.json;
const pipelineData = $('Parse Pipeline Request').item.json;

// Jira 응답에서 이슈 키 추출
const issueKey = jiraResponse.data?.key || jiraResponse.key || 'UNKNOWN';
const issueUrl = jiraResponse.data?.url || jiraResponse.url || '';

// 브랜치 이름 생성 (Jira 이슈 키 기반)
const branchName = `fix/${issueKey.toLowerCase()}`;

return {
  json: {
    ...pipelineData,
    issueKey,
    issueUrl,
    branchName
  }
};

