const claudeResponse = $input.item.json;
const pipelineData = $('Extract Jira Key').item.json;

// Claude 응답에서 MR URL 추출
const response = claudeResponse.content || claudeResponse.response || claudeResponse.output || '';
const mrUrlMatch = response.match(/https:\/\/gitlab[^\s)]+merge_requests\/\d+/);
const mrUrl = mrUrlMatch ? mrUrlMatch[0] : null;

// MR URL이 실제로 있어야만 성공
const success = !!mrUrl;

console.log('Claude response length:', response.length);
console.log('MR URL found:', mrUrl);
console.log('Success:', success);

return {
  json: {
    ...pipelineData,
    success,
    mrUrl,
    claudeResponse: response.substring(0, 2000) // 로그용
  }
};
